@function map-safe-get($map, $key) {
  @if (type-of($map) == 'map' or (type-of($map) == 'list' and length($map) == 0)) {
    @if (map-has-key($map, $key)) {
      @return map-get($map, $key);
    }
    @else {
      @error 'Key: `#{$key}` is not available in `#{$map}`';
    }
  }
  @else {
    @error '`#{$map}` is not a valid map';
  }
}

@function powerNumber($number, $exp) {
  $value: 1;

  @if $exp > 0 {
    @for $i from 1 through $exp {
      $value: $value * $number;
    }
  } @else if $exp < 0 {
    @for $i from 1 through -$exp {
      $value: math.div($value, $number);
    }
  }

  @return $value;
}

@function xy-cell-base($size: full) {
  @if ($size == 'auto') {
    @return 1 1 0;
  }
  @else if ($size == 'grow') {
    @return 1 0 auto;
  }
  @else if ($size == 'shrink' or $size == 'full' or zf-is-fraction($size, $allow-no-denominator: true)) {
    @return 0 0 auto;
  }
  @return null;
}

@function bulmaFindDarkColor($color, $base-l: 29%) {
  @if meta.type-of($color) == "color" {
    $luminance: bulmaColorLuminance($color);
    $luminance-delta: 0.53 - $luminance;
    $target-l: math.round($base-l + $luminance-delta * 53);

    @return color.change($color, $lightness: max($base-l, $target-l));
  }

  @return $text-strong;
}

@mixin fixed-grid-properties($suffix: "") {
  @for $i from 1 through $max-column-count {
    &.#{iv.$class-prefix}has-#{$i}-cols#{$suffix} {
      > .#{iv.$class-prefix}grid {
        @include cv.register-var("grid-column-count", #{$i});
      }
    }
  }
}

@function set-notification-text-color($color) {
  @if (lightness($color) > 70) {
    @return $gray-800;
  } @else {
    @return $white;
  }
}

@function color-level($color: $primary, $level: 0) {
  $color-base: if($level > 0, $black, $white);
  $level: abs($level);

  @return mix($color-base, $color, $level);
}

@mixin form-validation-state-selector($state) {
  @if ($state == 'valid' or $state == 'invalid') {
    .was-validated #{if(&, "&", "")}:#{$state},
    #{if(&, "&", "")}.is-#{$state} {
      @content;
    }
  } @else {
    #{if(&, "&", "")}.is-#{$state} {
      @content;
    }
  }
}

@function _unpack-shorthand($shorthand) {
  @if length($shorthand) == 1 {
    @return nth($shorthand, 1) nth($shorthand, 1) nth($shorthand, 1) nth($shorthand, 1);
  } @else if length($shorthand) == 2 {
    @return nth($shorthand, 1) nth($shorthand, 2) nth($shorthand, 1) nth($shorthand, 2);
  } @else if length($shorthand) == 3 {
    @return nth($shorthand, 1) nth($shorthand, 2) nth($shorthand, 3) nth($shorthand, 2);
  } @else {
    @return $shorthand;
  }
}

@mixin _assert-starts-at-zero($map, $map-name: "$grid-breakpoints") {
  @if length($map) > 0 {
    $values: map-values($map);
    $first-value: nth($values, 1);
    @if $first-value != 0 {
      @warn "First breakpoint in #{$map-name} must start at 0, but starts at #{$first-value}.";
    }
  }
}

@function breakpoint-next($name, $breakpoints: $grid-breakpoints, $breakpoint-names: map-keys($breakpoints)) {
  $n: index($breakpoint-names, $name);
  @if not $n {
    @error "breakpoint `#{$name}` not found in `#{$breakpoints}`";
  }
  @return if($n < length($breakpoint-names), nth($breakpoint-names, $n + 1), null);
}

@mixin make-col($size: false, $columns: $grid-columns) {
  @if $size {
    flex: 0 0 auto;
    width: percentage(divide($size, $columns));

  } @else {
    flex: 1 1 0;
    max-width: 100%;
  }
}

@mixin make-col-auto() {
  flex: 0 0 auto;
  width: auto;
}

@function motion($name, $mode: productive, $easings: $easings) {
  @if map.has-key($easings, $name) {
    $easing: map.get($easings, $name);
    @if map.has-key($easing, $mode) {
      @return map.get($easing, $mode);
    } @else {
      @error 'Unable to find a mode for the easing #{$easing} called: #{$mode}.';
    }
  } @else {
    @error 'Unable to find an easing named #{$name} in our supported easings.';
  }
}

@mixin viewer-slider-size($image-number: 36) {
  @for $s from 1 through ($image-number) {
    .viewer-slider[max='#{$image-number}'][value='#{$s}'] + .viewer-image {
      background-position-y: percentage((($s)-1) * 1/(($image-number)-1));
    }
  }
}

@function str-replace($string, $search, $replace: "") {
  $index: str-index($string, $search);

  @if $index {
    @return str-slice($string, 1, $index - 1) + $replace + str-replace(str-slice($string, $index + str-length($search)), $search, $replace);
  }

  @return $string;
}

@mixin hook-button-text(){

    position: relative;

    &::before {
        content: "";
        position: absolute;
        bottom: 0;
        left: 0;
        right: 100%;
        border-bottom: $button-text-border-width solid $button-text-border;
        transition: right 0.3s ease-out;
    }

}

@function escape-svg($string) {
  @if str-index($string, "data:image/svg+xml") {
    @each $char, $encoded in $escaped-characters {
      // Do not escape the url brackets
      @if str-index($string, "url(") == 1 {
        $string: url("#{str-replace(str-slice($string, 6, -3), $char, $encoded)}");
      } @else {
        $string: str-replace($string, $char, $encoded);
      }
    }
  }

  @return $string;
}

// Helper function to replace negative values with 0
@function valid-radius($radius) {
  $return: ();
  @each $value in $radius {
    @if type-of($value) == number {
      $return: append($return, max($value, 0));
    } @else {
      $return: append($return, $value);
    }
  }
  @return $return;
}

@function breakpoint-next(
  $name,
  $breakpoints: $grid-breakpoints,
  $breakpoint-names: map.keys($breakpoints)
) {
  $n: list.index($breakpoint-names, $name);
  @if $n != null and $n < list.length($breakpoint-names) {
    @return list.nth($breakpoint-names, $n + 1);
  }
  @return null;
}

@function breakpoint-prev(
  $name,
  $breakpoints: $grid-breakpoints,
  $breakpoint-names: map.keys($breakpoints)
) {
  $n: list.index($breakpoint-names, $name);
  @if $n != null and $n > 1 {
    @return list.nth($breakpoint-names, $n - 1);
  }
  @return null;
}

@mixin element-invisible(
  $enforce: true
) {
  $important: if($enforce, '!important', null);

  position: absolute #{$important};
  width: 1px #{$important};
  height: 1px #{$important};
  padding: 0 #{$important};
  overflow: hidden #{$important};
  clip: rect(0, 0, 0, 0) #{$important};
  white-space: nowrap #{$important};
  border: 0 #{$important};
}

@mixin show-for($size) {
  $size: map-get($breakpoints, $size);
  // Max value is 0.2px under the next breakpoint (0.02 / 16 = 0.00125).
  // Use a precision under 1px to support browser zoom, but not to low to avoid rounding.
  // See https://github.com/foundation/foundation-sites/issues/11313
  $size: -zf-bp-to-em($size) - 0.00125;

  @include breakpoint($size down) {
    display: none !important;
  }
}

@if (type-of($inuit-wrapper-width) != number) {
  @error "`#{$inuit-wrapper-width}` needs to be a number.";
}

.o-wrapper {
  @include inuit-clearfix();
  padding-right: $inuit-wrapper-padding;
  padding-left:  $inuit-wrapper-padding;
  margin-right: auto;
  margin-left:  auto;
  max-width: $inuit-wrapper-width;
}

@function bulmaFindLightColor($color, $l: 96%) {
  @if meta.type-of($color) == "color" {
    $l: 96%;

    @if color.channel($color, "lightness", $space: hsl) > 96% {
      $l: color.channel($color, "lightness", $space: hsl);
    }

    @return color.change($color, $lightness: $l);
  }

  @return $background;
}

@mixin ltr-property($property, $spacing, $right: true) {
  $normal: "right";
  $opposite: "left";
  @if not $right {
    $normal: "left";
    $opposite: "right";
  }

  @if iv.$rtl {
    #{$property}-#{$opposite}: $spacing;
  } @else {
    #{$property}-#{$normal}: $spacing;
  }
}

@mixin register-rgb($name, $value) {
  @include register-var(
    $name,
    (
      color.channel($value, "red", $space: rgb),
      color.channel($value, "green", $space: rgb),
      color.channel($value, "blue", $space: rgb)
    ),
    "",
    "-rgb"
  );
}

@mixin generate-basic-palette($name, $base, $invert: null) {
  @include register-base-color($name, $base);

  @if $invert {
    @include register-var(
      $name,
      color.channel($invert, "lightness", $space: hsl),
      "",
      "-invert-l"
    );
    @include register-var("#{$name}-invert", $invert);
  }
}

@mixin typography-size($target: "") {
  @each $size in dv.$sizes {
    $i: list.index(dv.$sizes, $size);
    $suffix: "";
    @if $target != "" {
      $suffix: "-" + $target;
    }

    .#{iv.$class-prefix}#{iv.$helpers-prefix}size-#{$i}#{$suffix} {
      font-size: $size !important;
    }
  }
}

@mixin text-color-variant($name: ".text-primary", $color: $primary-color) {
  #{$name} {
    color: $color !important;
  }

  a#{$name} {
    &:focus,
    &:hover {
      color: darken($color, 5%);
    }
    &:visited {
      color: lighten($color, 5%);
    }
  }
}

// scss-docs-start border-radius-mixins
@mixin border-radius($radius: $border-radius, $fallback-border-radius: false) {
  @if $enable-rounded {
    border-radius: valid-radius($radius);
  }
  @else if $fallback-border-radius != false {
    border-radius: $fallback-border-radius;
  }
}

@mixin loader {
  animation: spinAround 500ms infinite linear;
  border: 2px solid cv.getVar("loading-color");
  border-radius: cv.getVar("radius-rounded");
  border-right-color: transparent;
  border-top-color: transparent;
  content: "";
  display: block;
  height: 1em;
  position: relative;
  width: 1em;
}

&::-webkit-progress-bar {
  background: transparent;
  border-radius: $border-radius;
}

&::-webkit-progress-value {
  background: $primary-color;
  border-radius: $border-radius;
}

&::-moz-progress-bar {
  background: $primary-color;
  border-radius: $border-radius;
}

@mixin hook-tab(){

    position: relative;

    &::before {
        content: "";
        position: absolute;
        bottom: 0;
        left: $tab-margin-horizontal;
        right: 0;
        border-bottom: $tab-border-width solid $tab-border;
    }

}

@each $step, $value in $steps {
  :host(#{$host-selector}[#{$group}='#{$step}']) {
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}-context',
      custom-property.get-var(
        'layout-#{$group}-#{$property}-#{$step}',
        $value
      )
    );
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}',
      custom-property.get-var('layout-#{$group}-#{$property}-context')
    );
  }
}

@each $key, $value in $theme {
  @if $key == 'color-scheme' {
    @include custom-property.declaration($key, $value);

    color-scheme: custom-property.get-var($key, $value);
  } @else if meta.type-of($value) == color {
    @include custom-property.declaration($key, $value);
  }
}

&::before,
    &::after {
      position: absolute;
      display: block;
      background: $layer-hover;
      block-size: 1px;
      content: '';
      inline-size: 100%;
      inset-inline-start: 0;
      transition: background motion(standard, productive) $duration-fast-02;

      @media screen and (prefers-reduced-motion: reduce) {
        transition: none;
      }
    }

&:disabled,
    &:hover:disabled,
    &:focus:disabled,
    &.#{$prefix}--btn--disabled,
    &.#{$prefix}--btn--disabled:hover,
    &.#{$prefix}--btn--disabled:focus {
      background: transparent;
      color: $text-disabled;
      outline: none;
    }

&:disabled,
    &:hover:disabled,
    &:focus:disabled,
    &.#{$prefix}--btn--disabled,
    &.#{$prefix}--btn--disabled:hover,
    &.#{$prefix}--btn--disabled:focus {
      border-color: transparent;
      background: transparent;
      color: $text-disabled;
      outline: none;
    }

&::before {
  z-index: 0;
  border-radius: 0;
  block-size: 100%;
  border-block-end: convert.to-rem(1px) solid $border-inverse;
  border-block-start: convert.to-rem(1px) solid $border-inverse;
  box-shadow: inset 0 0 0 convert.to-rem(1px) $layer-hover;
  content: '';
  inline-size: 100%;
}

@mixin hook-inverse-component-article(){

    .uk-article-title {
        @if(meta.mixin-exists(hook-inverse-article-title)) {@include hook-inverse-article-title();}
    }

    .uk-article-meta {
        color: $inverse-article-meta-color;
        @if(meta.mixin-exists(hook-inverse-article-meta)) {@include hook-inverse-article-meta();}
    }

}

@function str-replace($string, $search, $replace: '') {
    $index: string.index($string, $search);

    @if $index {
        @return string.slice($string, 1, $index - 1) + $replace +
            str-replace(string.slice($string, $index + string.length($search)), $search, $replace);
    }

    @return $string;
}

@else {
  $previous-breakpoint: breakpoint-prev($key, $breakpoints);
  $previous-column-count: get-column-count(
    $breakpoints,
    $previous-breakpoint
  );
  $previous-span: $previous-column-count * $percent;

  @if $span != $previous-span {
    @include breakpoint($key) {
      --cds-grid-columns: #{$span};

      grid-column: span list.slash($span, span) #{$span};
    }
  }
}

@if meta.type-of($value) == map {
  $fallback: map.get($value, fallback);
  $theme-values: map.get($value, values);

  @each $theme-value in $theme-values {
    $value: map.get($theme-value, value);

    @if theme.matches(map.get($theme-value, theme), $theme) and
      meta.type-of($value) ==
      color
    {
      @include custom-property.declaration($key, $value);
    }
  }
}

&::after {
  position: absolute;
  background: $focus;
  block-size: 1px;
  content: '';
  inline-size: convert.to-rem(12px);
  inset-block-end: 2px;
  opacity: 0;
  transition: opacity $duration-fast-01 motion(standard, productive);

  @media screen and (prefers-reduced-motion: reduce) {
    transition: none;
  }
}

@mixin bx--snippet {
  @include type-style('code-01');

  position: relative;
  background-color: $layer;
  inline-size: 100%;
  max-inline-size: convert.to-rem(768px);
  // Allow shrinking in grid/flex parents (e.g. Stack) so long pre content does not force layout width
  min-inline-size: 0;
}

@else if map.has-key($breakpoints, $name) {
  $breakpoint: map.get($breakpoints, $name);
  $width: map.get($breakpoint, width);
  @if is-smallest-breakpoint($name, $breakpoints) {
    @content;
  } @else {
    @media (min-width: $width) {
      @content;
    }
  }
}
